section.json_schema:
{
  "contract_type": "[vendor|customer|employment|dpa|general]",
  "risk_level": "[high|medium|low]",
  "risk_score": 0-100,
  "confidence_score": 0.0-1.0,

  "parties": {
    "party_a": {
      "name": "Legal entity name",
      "role": "Buyer|Seller|Employer|Employee|etc.",
      "jurisdiction": "State/Country"
    },
    "party_b": { ... }
  },

  "key_dates": {
    "effective_date": "YYYY-MM-DD or 'Not specified'",
    "termination_date": "YYYY-MM-DD or 'Not specified'",
    "notice_period_days": 30,
    "renewal_terms": "Description of renewal mechanism"
  },

  "critical_issues": [
    {
      "category": "Liability|Payment|Termination|Compliance|Other",
      "severity": "critical|high|medium",
      "title": "Brief issue title",
      "description": "Detailed description of the issue",
      "clause_reference": "Section X.Y or page number",
      "recommendation": "Specific action to take",
      "risk_impact": "Explanation of potential consequences"
    }
  ],

  "warnings": [
    {
      "category": "...",
      "severity": "medium|low",
      "title": "...",
      "description": "...",
      "clause_reference": "...",
      "recommendation": "..."
    }
  ],

  "positive_findings": [
    {
      "category": "...",
      "title": "...",
      "description": "Favorable term or protective clause",
      "clause_reference": "..."
    }
  ],

  "missing_clauses": [
    {
      "clause_type": "Force Majeure|Confidentiality|etc.",
      "importance": "critical|recommended|optional",
      "reason": "Why this clause should be included",
      "suggested_language": "Brief example of what should be added"
    }
  ],

  "financial_summary": {
    "total_contract_value": "$X or 'Not specified'",
    "payment_terms": "Net X days",
    "payment_schedule": "Description",
    "penalties_fees": "Description of late fees, penalties, etc."
  },

  "key_obligations": {
    "our_obligations": ["Obligation 1", "Obligation 2", ...],
    "their_obligations": ["Obligation 1", "Obligation 2", ...]
  },

  "recommendations": [
    {
      "priority": "high|medium|low",
      "action": "negotiate|approve|reject|clarify",
      "description": "Specific recommendation",
      "rationale": "Why this is important"
    }
  ],

  "overall_assessment": "2-3 sentence executive summary"
}
